SELECT store_name AS storeName, ${column} AS `value` FROM amz_replenishment_snapshot WHERE warehouse_sku = #{warehouseSku} AND current_flag = 1 AND store_name IS NOT NULL AND store_name != ''
AND store_name IN #{s}
ORDER BY ${column} DESC LIMIT 10

SELECT s.store_name AS storeName,
       ROUND(SUM(COALESCE(s.`${breakdownColumn}`, 0)), 2) AS `value`
FROM amz_replenishment_snapshot s
LEFT JOIN amz_replenishment_override o ON CAST(s.sid AS CHAR) COLLATE utf8mb4_unicode_ci = o.sid AND s.seller_sku = o.seller_sku

    and s.current_flag = 1
    and s.warehouse_sku = #{warehouseSkuExact}
