    and refund_rate_90d between #{refund_rate_90d_val} and #{refund_rate_90d_val2} and refund_rate_90d is null  and refund_rate_90d is not null  and refund_rate_90d ${refund_rate_90d_op} #{refund_rate_90d_val} 
